```zig
const std = @import("std");

var global_allocator = std.heap.page_allocator;
var cache: ?std.StringHashMap([]u8) = null;

pub fn init() void {
    cache = std.StringHashMap([]u8).init(global_allocator);
}

pub fn getData(key: []const u8) anyerror![]u8 {
    if (cache.?.get(key)) |val| return val;
    var buf = try global_allocator.alloc(u8, 1024);
    var file = try std.fs.cwd().openFile(key, .{});
    var bytes_read = try file.read(buf);
    _ = bytes_read;
    try cache.?.put(key, buf);
    return buf;
}

pub fn main() !void {
    init();
    var result = try getData("config.txt");
    std.debug.print("{s}\n", .{result});
}
```

I have a Zig program that processes a large file (500MB+) of newline-delimited JSON records. Each record needs to be parsed, validated, and written to an output file. It's currently too slow. Here's the core loop:

```zig
fn processFile(path: []const u8) !void {
    const allocator = std.heap.page_allocator;
    const file = try std.fs.cwd().openFile(path, .{});
    defer file.close();
    const out = try std.fs.cwd().createFile("output.json", .{});
    defer out.close();

    var buf: [65536]u8 = undefined;
    while (try file.reader().readUntilDelimiterOrEof(&buf, '\n')) |line| {
        const parsed = try std.json.parseFromSlice(std.json.Value, allocator, line, .{});
        defer parsed.deinit();
        if (isValid(parsed.value)) {
            try std.json.stringify(parsed.value, .{}, out.writer());
            try out.writer().writeByte('\n');
        }
    }
}
```

