const std = @import("std");

const PERIPHERAL_BASE: usize = 0x4000_0000;

var status_flag: bool = false;

const GPIORegisters = struct {
    mode: u32,
    output: u32,
    input: u32,
    speed: u32,
};

fn readGPIO() GPIORegisters {
    const regs: *GPIORegisters = @ptrFromInt(PERIPHERAL_BASE);
    return regs.*;
}

fn waitForReady() void {
    const status: *u32 = @ptrFromInt(PERIPHERAL_BASE + 0x10);
    while (status.* & 0x01 == 0) {}
}

fn processData(raw: [*]u8, len: usize) u32 {
    var sum: u32 = 0;
    var i: usize = 0;
    while (i < len) : (i += 4) {
        const val: *u32 = @ptrCast(raw + i);
        sum += val.*;
    }
    return sum;
}

fn setFlag() void {
    status_flag = true;
}

pub fn main() void {
    waitForReady();
    const gpio = readGPIO();
    std.debug.print("mode: {}\n", .{gpio.mode});

    var buf: [256]u8 = undefined;
    const total = processData(&buf, 256);
    std.debug.print("total: {}\n", .{total});
}
